    // --- Utility & Validation Methods ---

    private Map<String, String> parseQueryParams(Uri uri) {
        Map<String, String> params = new HashMap<>();
        try {
            for (String paramName : uri.getQueryParameterNames()) {
                String value = uri.getQueryParameter(paramName);
                if (value != null) {
                    params.put(sanitizeInput(paramName), sanitizeInput(value));
                }
            }
        } catch (Exception e) {
            Log.e(TAG, "Error parsing query parameters", e);
        }
        return params;
    }

    private String sanitizeInput(String input) {
        if (input == null) return null;
        // Remove potential script injection and trim
        return input.replaceAll("[<>\"';&|]", "")
                .replaceAll("\\.\\.+", "")
                .replaceAll("javascript:", "")
                .trim();
    }

    private boolean isValidId(String id) {
        if (id == null || id.isEmpty()) return false;
        // Allow alphanumeric IDs with hyphens and underscores, max 64 chars
        return id.matches("^[a-zA-Z0-9_-]{1,64}$");
    }

    private boolean isValidTransactionId(String txnId) {
        if (txnId == null || txnId.isEmpty()) return false;
        return txnId.matches("^[a-zA-Z0-9_-]{1,128}$");
    }

